    uint32_t width = static_cast<uint32_t>(inputShape.GetDim(3));
    uint32_t spatialSize = height * width;
    uint32_t totalLength = batchSize * channels * spatialSize;

    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t tileLen = (spatialSize < maxTile) ? spatialSize : maxTile;
    tileLen = AlignDown(tileLen, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = (spatialSize < ALIGN_ELEMS) ? spatialSize : ALIGN_ELEMS;

    uint32_t numTiles = CeilDiv(spatialSize, tileLen);
    uint32_t blockDim = batchSize * channels;
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    // Use setter methods required by the tiling data macro
    tiling.set_batchSize(batchSize);
    tiling.set_channels(channels);
    tiling.set_spatialSize(spatialSize);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
